"""
# Support for the directory protocol holding captured metrics.

# The `metrics` image form of a factor holds archives of captured measurements in addition
# to the reports generated by measure. This module provides the necessary support for
# collecting the record sets associated with a metrics source.

# Primarily used by &.aggregate to form the constituents record for reporting.
"""

def factor_records(root):
	"""
	# Scan the tree, &root, for data files and select the segment
	# from &root that can be used to identify the origin of
	# the record.

	# Yields the path and segment identifying the record set.
	"""

	# Any paths leading a regular file is either a factor path or a record type.
	for d, files in root.fs_index():
		qpath = d.segment(root)

		# The records are identified with a leading dot while the
		# the factor paths of the data source (usually a test) do not.
		# Exception cases are recognized by the absence of an origin factor.
		if files and qpath.identifier[:1] == '.':
			yield root, qpath

def find_record_sets(path):
	"""
	# Scan each data set for capture records.

	# [ Parameters ]
	# /path/
		# The path to the directory containing the record sets relative to a process identifier.
	"""

	for dataset in path.fs_list('void')[0]:
		yield from factor_records(dataset)

if __name__ == '__main__':
	import sys
	from fault.system import files
	for path, seg in find_record_sets(files.root@sys.argv[1]):
		print((path//seg).fs_list())
